// Parsear la respuesta de Claude y enriquecer con datos del webhook
const claudeResponse = $input.first().json;
const rawContent = claudeResponse.content?.[0]?.text?.trim() ?? '';

// Siempre disponible sin importar la ruta (audio o texto)
const webhookData = $('Webhook WhatsApp').first().json;
const usuarioTelefono = webhookData.body?.From ?? webhookData.From ?? '';
const fechaHoy = $now.toISO().split('T')[0];
const mesActual = $now.toISO().substring(0, 7);

let parsed;
try {
  // Limpiar markdown si Claude lo envuelve con ```
  const cleaned = rawContent
    .replace(/```json\n?/g, '')
    .replace(/```\n?/g, '')
    .trim();

  const jsonMatch = cleaned.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    parsed = JSON.parse(jsonMatch[0]);
  } else {
    throw new Error('No se encontró JSON en la respuesta de Claude');
  }
} catch (e) {
  parsed = {
    error: true,
    mensaje_error: e.message
  };
}

return [{
  json: {
    ...parsed,
    usuario_telefono: usuarioTelefono,
    fecha_hoy: fechaHoy,
    mes_actual: mesActual
  }
}];

// Calcular métricas del mes para responder CONSULTAS
const rows = $input.all();
const registroIA = $('Parsear Respuesta IA').first().json;

let totalGastos = 0;
let totalIngresos = 0;
const porCategoria = {};

rows.forEach(item => {
  const tipo = item.json.tipo;
  const categoria = item.json.categoria;
  const valor = parseFloat(item.json.valor) || 0;

  if (tipo === 'gasto') {
    totalGastos += valor;
    porCategoria[categoria] = (porCategoria[categoria] || 0) + valor;
  } else if (tipo === 'ingreso') {
    totalIngresos += valor;
  }
});

const balance = totalIngresos - totalGastos;
const porcentajeGastado = totalIngresos > 0
  ? parseFloat(((totalGastos / totalIngresos) * 100).toFixed(1))
  : 0;

const categoriasSorted = Object.entries(porCategoria)
  .sort((a, b) => b[1] - a[1]);

const hoy = new Date();
const diasEnMes = new Date(hoy.getFullYear(), hoy.getMonth() + 1, 0).getDate();
const diasRestantes = diasEnMes - hoy.getDate();
const gastosDiarioRestante = (diasRestantes > 0 && balance > 0)
  ? Math.round(balance / diasRestantes)
  : 0;

return [{
  json: {
    totalGastos,
    totalIngresos,
    balance,
    porcentajeGastado,
    categoriasSorted,
    diasRestantes,
    gastosDiarioRestante,
    registroIA
  }
}];

// Generar mensaje de respuesta para CONSULTAS
const m = $input.first().json;
const r = m.registroIA;

function fmt(n) {
  return '$' + Math.abs(Math.round(n)).toLocaleString('es-CO');
}

function emoji(cat) {
  const map = {
    comida: '🍔', transporte: '🚗', vivienda: '🏠', salud: '💊',
    ocio: '🎬', ropa: '👕', educacion: '📚', servicios: '💡',
    salario: '💼', otros: '📦'
  };
  return map[cat?.toLowerCase()] || '📦';
}

let msg = '';

switch (r.tipo_consulta) {
  case 'resumen_mes':
  case 'cuanto_llevo':
    msg = `📊 *Resumen de este mes*\n\n`;
    msg += `💰 Ingresos: ${fmt(m.totalIngresos)}\n`;
    msg += `💸 Gastos: ${fmt(m.totalGastos)}\n`;
    msg += `✅ Balance: ${fmt(m.balance)}\n`;
    msg += `📈 Llevas el ${m.porcentajeGastado}%\n`;
    if (m.categoriasSorted.length > 0) {
      msg += `\n📂 *Por categoría:*\n`;
      m.categoriasSorted.slice(0, 5).forEach(([cat, val]) => {
        const pct = m.totalGastos > 0
          ? ((val / m.totalGastos) * 100).toFixed(0)
          : 0;
        msg += `${emoji(cat)} ${cat}: ${fmt(val)} (${pct}%)\n`;
      });
    }
    msg += `\n📅 Quedan ${m.diasRestantes} días`;
    if (m.gastosDiarioRestante > 0) {
      msg += `\n💡 Puedes gastar ${fmt(m.gastosDiarioRestante)}/día`;
    }
    break;

  case 'mayor_gasto':
    msg = `🔍 *Mayor gasto este mes:*\n\n`;
    if (m.categoriasSorted.length === 0) {
      msg += `No hay gastos registrados este mes.`;
    } else {
      m.categoriasSorted.slice(0, 5).forEach(([cat, val], i) => {
        msg += `${i + 1}. ${emoji(cat)} ${cat}: ${fmt(val)}\n`;
      });
    }
    break;

  case 'cuanto_queda':
    msg = `💼 *Te queda disponible:*\n\n`;
    msg += `*${fmt(m.balance)}*\n\n`;
    msg += `📅 Para ${m.diasRestantes} días restantes`;
    if (m.gastosDiarioRestante > 0) {
      msg += `\n💡 ${fmt(m.gastosDiarioRestante)}/día`;
    }
    break;

  default:
    msg = `📊 *Balance actual:* ${fmt(m.balance)}\n`;
    msg += `Ingresos: ${fmt(m.totalIngresos)} | Gastos: ${fmt(m.totalGastos)}`;
}

return [{ json: { mensaje: msg, usuario_telefono: r.usuario_telefono } }];

// Calcular métricas incluyendo el nuevo registro recién guardado
const rows = $('Leer Mes (Registro)').all();
const registroIA = $('Parsear Respuesta IA').first().json;

let totalGastos = 0;
let totalIngresos = 0;
const porCategoria = {};

// Datos históricos del mes (antes del nuevo registro)
rows.forEach(item => {
  const tipo = item.json.tipo;
  const categoria = item.json.categoria;
  const valor = parseFloat(item.json.valor) || 0;

  if (tipo === 'gasto') {
    totalGastos += valor;
    porCategoria[categoria] = (porCategoria[categoria] || 0) + valor;
  } else if (tipo === 'ingreso') {
    totalIngresos += valor;
  }
});

// Sumar el nuevo registro (recién guardado en Sheets)
const nuevoValor = parseFloat(registroIA.valor) || 0;
if (registroIA.tipo === 'gasto') {
  totalGastos += nuevoValor;
  porCategoria[registroIA.categoria] =
    (porCategoria[registroIA.categoria] || 0) + nuevoValor;
} else if (registroIA.tipo === 'ingreso') {
  totalIngresos += nuevoValor;
}

const balance = totalIngresos - totalGastos;
const porcentajeGastado = totalIngresos > 0
  ? parseFloat(((totalGastos / totalIngresos) * 100).toFixed(1))
  : 0;

const categoriasSorted = Object.entries(porCategoria)
  .sort((a, b) => b[1] - a[1]);

const hoy = new Date();
const diasEnMes = new Date(hoy.getFullYear(), hoy.getMonth() + 1, 0).getDate();
const diasRestantes = diasEnMes - hoy.getDate();
const gastosDiarioRestante = (diasRestantes > 0 && balance > 0)
  ? Math.round(balance / diasRestantes)
  : 0;

return [{
  json: {
    totalGastos,
    totalIngresos,
    balance,
    porcentajeGastado,
    categoriasSorted,
    diasRestantes,
    gastosDiarioRestante,
    registroIA
  }
}];

// Generar mensaje de confirmación para REGISTROS nuevos
const m = $input.first().json;
const r = m.registroIA;

function fmt(n) {
  return '$' + Math.abs(Math.round(n)).toLocaleString('es-CO');
}

function emoji(cat) {
  const map = {
    comida: '🍔', transporte: '🚗', vivienda: '🏠', salud: '💊',
    ocio: '🎬', ropa: '👕', educacion: '📚', servicios: '💡',
    salario: '💼', otros: '📦'
  };
  return map[cat?.toLowerCase()] || '📦';
}

let msg = '';

if (r.error) {
  // Claude no pudo clasificar el mensaje
  msg = `❌ No entendí tu mensaje.\n\n`;
  msg += `Intenta así:\n`;
  msg += `• _"gasté 30 mil en comida"_\n`;
  msg += `• _"pagué 800 mil de arriendo"_\n`;
  msg += `• _"recibí 2 millones de salario"_\n`;
  msg += `• _"¿cuánto llevo este mes?"_`;
} else {
  const accionEmoji = r.tipo === 'gasto' ? '💸' : '💰';
  const accion = r.tipo === 'gasto' ? 'Gasto registrado ✅' : 'Ingreso registrado ✅';

  msg = `${accionEmoji} *${accion}*\n`;
  msg += `${emoji(r.categoria)} Categoría: *${r.categoria}*\n`;
  msg += `💵 Valor: *${fmt(r.valor)}*\n`;
  if (r.descripcion) msg += `📝 ${r.descripcion}\n`;

  msg += `\n📊 *Resumen del mes:*\n`;
  msg += `💰 Ingresos: ${fmt(m.totalIngresos)}\n`;
  msg += `💸 Gastos: ${fmt(m.totalGastos)}\n`;
  msg += `✅ Balance: ${fmt(m.balance)}\n`;
  msg += `📈 Llevas el *${m.porcentajeGastado}%* del ingreso\n`;

  // Alertas según porcentaje gastado
  if (m.porcentajeGastado > 100) {
    msg += `\n🚨 *Alerta:* Superaste los ingresos del mes`;
  } else if (m.porcentajeGastado > 80) {
    msg += `\n⚠️ *Cuidado:* Llevas más del 80% gastado`;
  } else if (m.porcentajeGastado > 60) {
    msg += `\n📌 Vigila los gastos`;
  } else {
    msg += `\n💪 Vas muy bien este mes`;
  }
}

return [{ json: { mensaje: msg, usuario_telefono: r.usuario_telefono } }];
